import React, { useEffect, useState } from 'react';
import WebSocketService from '../services/WebSocketService';
import api from '../services/api';

const Notifications = () => {
  const [notifications, setNotifications] = useState([]);
  const [filter, setFilter] = useState('all');
  const [sortBy, setSortBy] = useState('timestamp');
  const [sortOrder, setSortOrder] = useState('desc');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchNotifications = async () => {
      try {
        const response = await api.get('/notifications');
        setNotifications(response.data);
      } catch (err) {
        console.error('Error fetching notifications:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchNotifications();

    WebSocketService.connect(() => {
      WebSocketService.subscribe('/topic/alerts', (alert) => {
        setNotifications(prev => [alert, ...prev].slice(0, 50));
      });
    });

    return () => WebSocketService.disconnect();
  }, []);

  const filteredNotifications = filter === 'all'
    ? notifications
    : notifications.filter(n => n.severity === filter);

  const sortedNotifications = [...filteredNotifications].sort((a, b) => {
    if (sortBy === 'timestamp') {
      return sortOrder === 'desc'
        ? new Date(b.timestamp) - new Date(a.timestamp)
        : new Date(a.timestamp) - new Date(b.timestamp);
    }
    if (sortBy === 'severity') {
      return sortOrder === 'desc'
        ? b.severity.localeCompare(a.severity)
        : a.severity.localeCompare(b.severity);
    }
    return 0;
  });

  const handleSort = (field) => {
    if (sortBy === field) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(field);
      setSortOrder('desc');
    }
  };

  return (
    <div className="space-y-6">
      <h2 className="g-title">Notifications</h2>
      <div className="flex space-x-4 mb-4">
        <select
          className="g-input"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        >
          <option value="all">All Severities</option>
          <option value="HIGH">High</option>
          <option value="MEDIUM">Medium</option>
          <option value="LOW">Low</option>
        </select>
      </div>
      <div className="stat-card">
        <h3 className="text-lg font-semibold mb-4">Recent Alerts</h3>
        {loading ? (
          <p className="text-gray-600">Loading notifications...</p>
        ) : sortedNotifications.length === 0 ? (
          <p className="text-gray-600">No notifications available.</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-gray-100">
                  <th className="p-2 cursor-pointer" onClick={() => handleSort('message')}>
                    Message {sortBy === 'message' && (sortOrder === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="p-2 cursor-pointer" onClick={() => handleSort('severity')}>
                    Severity {sortBy === 'severity' && (sortOrder === 'asc' ? '↑' : '↓')}
                  </th>
                  <th className="p-2 cursor-pointer" onClick={() => handleSort('timestamp')}>
                    Time {sortBy === 'timestamp' && (sortOrder === 'asc' ? '↑' : '↓')}
                  </th>
                </tr>
              </thead>
              <tbody>
                {sortedNotifications.map((notification, index) => (
                  <tr key={index} className="border-b">
                    <td className="p-2">{notification.message}</td>
                    <td className={`p-2 ${
                      notification.severity === 'HIGH' ? 'text-red-500' :
                      notification.severity === 'MEDIUM' ? 'text-yellow-500' :
                      'text-green-500'
                    }`}>
                      {notification.severity}
                    </td>
                    <td className="p-2">{new Date(notification.timestamp).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Notifications;
